})","ai_justification":"Service-to-CI associations are the data foundation for Now Assist ITOM impact analysis. Low association counts mean Now Assist cannot determine which CIs support which services.","remediation_guidance":"Map business services to CIs via svc_ci_assoc_list.do or by running Service Mapping. Ensure all business-critical services have CI associations. Without service-to-CI associations, Now Assist ITOM cannot determine which services are affected during incident response.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITOM","check_name":"ITOM Visibility / Health Entitlement","order":"150","check_script":"(function() {
    var t = new GlideRecord("samp_sw_license_metric");
    if (!t.isValid()) {
        return { status: "value_blocker", actualValue: "Required table samp_sw_license_metric not found", finding: "License Metric table is not available. Verify the SAM plugin is active." };
    }
    var matched = {};
    function collectMatches(keyword) {
        var gr = new GlideRecord("samp_sw_license_metric");
        gr.addQuery("name", "CONTAINS", keyword);
        gr.query();
        while (gr.next()) { matched[gr.getUniqueValue()] = true; }
    }
    collectMatches("itom");
    collectMatches("ITOM");
    var count = Object.keys(matched).length;
    var actualValue = count + " ITOM license metric records found";
    if (count > 0) {
        return { status: "ready", actualValue: actualValue, finding: count + " ITOM license metric record(s) found. ITOM entitlement appears active — manual confirmation with account team recommended." };
    } else {
        return { status: "needs_attention", actualValue: actualValue, finding: "No ITOM license metric records found. Manual entitlement confirmation recommended — without the correct ITOM SKU, Now Assist ITOM capabilities will not activate regardless of plugin installation or data quality." };
    }
})()","ai_justification":"ITOM Visibility/Health entitlement gates Now Assist ITOM AI features. Without the correct SKU, ITOM Now Assist capabilities will not activate.","remediation_guidance":"Contact your ServiceNow account team to confirm ITOM Visibility or ITOM Health SKU entitlement. Without the correct SKU, ITOM Now Assist capabilities will not activate regardless of plugin installation or data quality.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITOM","check_name":"Now Assist ITOM Plugin Status","order":"160","check_script":"(function(checkDef, dateFilter) {
    var checkPlugin = (function checkPlugin(storeScope, pluginSource) {    var result = { found: false, version: "", table: "" };    try {        var saGR = new GlideRecord("sys_store_app");        saGR.addQuery("scope", storeScope);        saGR.setLimit(1);        saGR.query();        if (saGR.next()) {            result.found = true;            result.version = saGR.getValue("version") || "";            result.table = "sys_store_app";            return result;        }    } catch(e1) {}    if (pluginSource) {        try {            var spGR = new GlideRecord("sys_plugins");            spGR.addQuery("source", pluginSource);            spGR.addQuery("active", true);            spGR.setLimit(1);            spGR.query();            if (spGR.next()) {                result.found = true;                result.version = spGR.getValue("version") || "";                result.table = "sys_plugins";                return result;            }        } catch(e2) {}    }    return result;});
    var result = checkPlugin("sn_itom_gen_ai", "sn_itom_gen_ai");
    if (result.found) {
        return {
            status: "ready",
            actualValue: "Now Assist for ITOM (" + "sn_itom_gen_ai" + ") installed | version: " + result.version + " | source: " + result.table,
            finding: "Now Assist for ITOM is installed. AI-assisted event correlation, alert grouping, and impact analysis are available."
        };
    } else {
        return {
            status: "not_ready",
            actualValue: "Now Assist for ITOM (sn_itom_gen_ai) not found in sys_store_app or sys_plugins",
            finding: "Now Assist for ITOM (sn_itom_gen_ai) not found. AI-assisted event correlation and impact analysis are unavailable."
        };
    }
})()","ai_justification":"Now Assist ITOM plugins must be active before AI-assisted event correlation, alert grouping, and impact analysis features can be used.","remediation_guidance":"Activate the Now Assist for ITOM plugin (sn_itom_gen_ai) via sys_plugins_list.do. Confirm ITOM Now Assist entitlement with your ServiceNow account team.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITOM","check_name":"Maintenance Window Configuration","order":"170","check_script":"(function(checkDef, dateFilter) {
    var ga = new GlideAggregate('cmn_schedule_maintenance');
    ga.addQuery('active', true);
    ga.addAggregate('COUNT');
    ga.query();
    var schedules = ga.next() ? parseInt(ga.getAggregate('COUNT')) : 0;

    var actualValue = schedules + ' active maintenance schedules defined';

    if (schedules >= 5) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: schedules + ' active maintenance schedules. Planned downtime is controlled — Now Assist ITOM event correlation training signal is protected from false-positive alert pollution.'
        };
    } else if (schedules >= 1) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'Only ' + schedules + ' active maintenance schedule(s) (target: 5+). Unscheduled maintenance events will generate false-positive alerts that degrade Now Assist ITOM AI correlation accuracy.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'No active maintenance schedules defined. Unscheduled maintenance generates false-positive alerts that pollute the Now Assist ITOM event correlation training corpus.'
        };
    }
})","ai_justification":"Unscheduled CIs generate false-positive alerts during patching and maintenance. These noise events pollute the alert corpus Now Assist uses for pattern recognition, degrading AI event grouping accuracy.","remediation_guidance":"Configure maintenance schedules for planned downtime via cmn_schedule_maintenance_list.do. Associate schedules with relevant CIs. Maintenance windows suppress false-positive alerts that would otherwise pollute the Now Assist ITOM event correlation training corpus.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITOM","check_name":"MID Server Health and Version Currency","order":"180","check_script":"(function(checkDef, dateFilter) {
    var gaTotal = new GlideAggregate('ecc_agent');
    gaTotal.addAggregate('COUNT');
    gaTotal.query();
    var total = gaTotal.next() ? parseInt(gaTotal.getAggregate('COUNT')) : 0;

    if (total === 0) {
        return {
            status: 'not_applicable',
            actualValue: 'No MID Servers found',
            finding: 'No MID Servers found on this instance. If this is a cloud-only deployment with no on-premise infrastructure, this check is not applicable. Otherwise, MID Servers are required for discovery and AI Agent-triggered remediation.'
        };
    }

    var gaHealthy = new GlideAggregate('ecc_agent');
    gaHealthy.addQuery('status', 'Up');
    gaHealthy.addQuery('validated', true);
    gaHealthy.addAggregate('COUNT');
    gaHealthy.query();
    var healthy = gaHealthy.next() ? parseInt(gaHealthy.getAggregate('COUNT')) : 0;

    var actualValue = total + ' total MID Servers | ' + healthy + ' up and validated';

    if (healthy >= 1) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: healthy + ' of ' + total + ' MID Servers are up and validated. Now Assist ITOM AI Agent-triggered discovery probes and remediation workflows can execute.'
        };
    } else {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: total + ' MID Server(s) found but none are up and validated. Now Assist ITOM AI Agent actions requiring on-premise access will fail until at least one MID Server is healthy.'
        };
    }
})","ai_justification":"MID Servers are the execution layer for AI Agent-triggered discovery probes and remediation workflows. Missing or down MID Servers cause agent infrastructure actions to fail silently.","remediation_guidance":"Deploy, validate, and upgrade MID Servers to the current instance version via ecc_agent_list.do. Ensure at least one MID Server is Up and validated per network zone. MID Servers are the execution layer for AI Agent-triggered discovery probes and remediation workflows.","is_manual":"0","is_clone_sensitive":"0"},{"module":"ITOM","check_name":"Alert Grouping Accuracy and CI Linkage","order":"190","check_script":"(function(checkDef, dateFilter) {
    var cutoff = new GlideDateTime();
    cutoff.addDaysUTC(-90);

    var gaTotal = new GlideAggregate('em_alert');
    gaTotal.addQuery('sys_created_on', '>=', cutoff.getValue());
    gaTotal.addAggregate('COUNT');
    gaTotal.query();
    var total = gaTotal.next() ? parseInt(gaTotal.getAggregate('COUNT')) : 0;

    if (total === 0) {
        return {
            status: 'not_applicable',
            actualValue: 'No alerts in last 90 days',
            finding: 'No alerts found in the last 90 days. Alert grouping and CI linkage cannot be assessed — Event Management may not be in use.'
        };
    }

    var gaGrouped = new GlideAggregate('em_alert');
    gaGrouped.addQuery('sys_created_on', '>=', cutoff.getValue());
    gaGrouped.addQuery('parent', '!=', '');
    gaGrouped.addAggregate('COUNT');
    gaGrouped.query();
    var grouped = gaGrouped.next() ? parseInt(gaGrouped.getAggregate('COUNT')) : 0;

    var gaCI = new GlideAggregate('em_alert');
    gaCI.addQuery('sys_created_on', '>=', cutoff.getValue());
    gaCI.addQuery('cmdb_ci', '!=', '');
    gaCI.addAggregate('COUNT');
    gaCI.query();
    var withCI = gaCI.next() ? parseInt(gaCI.getAggregate('COUNT')) : 0;

    var groupPct = Math.round((grouped / total) * 100);
    var ciPct = Math.round((withCI / total) * 100);

    var actualValue = total + ' alerts (last 90 days) | ' + grouped + ' grouped (' + groupPct + '%) | ' + withCI + ' with CI linked (' + ciPct + '%)';

    if (groupPct >= 30 && ciPct >= 80) {
        return {
            status: 'ready',
            actualValue: actualValue,
            finding: groupPct + '% of alerts grouped and ' + ciPct + '% linked to CIs (last 90 days). Now Assist ITOM has strong event correlation and CI context for AI-assisted pattern learning.'
        };
    } else if (groupPct >= 10 || ciPct >= 50) {
        return {
            status: 'needs_attention',
            actualValue: actualValue,
            finding: 'Alert grouping at ' + groupPct + '% and CI linkage at ' + ciPct + '% (targets: 30% grouping, 80% CI linkage). Now Assist ITOM correlation accuracy will be reduced — configure correlation rules and ensure CI discovery is current.'
        };
    } else {
        return {
            status: 'not_ready',
            actualValue: actualValue,
            finding: 'Alert grouping at ' + groupPct + '% and CI linkage at ' + ciPct + '% (last 90 days). Now Assist ITOM AI event correlation cannot learn meaningful patterns without grouped alerts linked to CIs.'
        };
    }
})","ai_justification":"AI Agents learn event correlation patterns from grouped alert history and CI linkages. Strong CI linkage means every alert can be traced to specific infrastructure for AI pattern learning.","remediation_guidance":"Enable alert grouping by configuring correlation rules. Ensure CIs are linked to alerts via discovery and alert management rules. Target: 30%+ grouping rate, 80%+ CI linkage rate on recent alerts. AI Agents learn event correlation patterns from grouped alert history.","is_manual":"0","is_clone_sensitive":"0"}];
    },
    type: 'AROPCheckSeeder_ITOM'
};
